    21	    /// <param name="snapshots">The list of snapshots to add to.</param>
    22	    /// <param name="targetSnapshot">The snapshot to add if unique.</param>
    23	    /// <param name="parameterStateValues">The list to collect parameter state values.</param>
    24	    public static void AddSnapshotIfUnique(
    25	        List<IParameterStateInvocationSnapshot> snapshots,
    26	        IParameterStateInvocationSnapshot targetSnapshot,
    27	        List<ParameterStateValue> parameterStateValues)
    28	    {
    29	        // IMPORTANT:
    30	        // The parameter state value must be collected *before* the duplicate snapshot check.
    31	        // Multiple parameters can share the same handler, which means the snapshot may be
    32	        // considered a duplicate and rejected below. However, the shared handler still needs
    33	        // to see *all* changed parameters via ParameterStateCollection.
    34	        // If we return early without collecting here, ParameterStateValues would be incomplete
    35	        // for shared handlers.
    36	        var parameterStateValue = targetSnapshot.GetParameterStateValue();
    37	        if (parameterStateValue.HasValue)
    38	        {
    39	            parameterStateValues.Add(parameterStateValue.Value);
    40	        }
    41	
    42	        foreach (var snapshot in snapshots)
    43	        {
    44	            if (ParameterHandlerUniquenessComparer.Default.Equals(snapshot, targetSnapshot))
    45	            {
    46	                // Handler is a duplicate, but parameter state value was already collected above
    47	                // to support shared handlers.
    48	                return;
    49	            }
    50	        }
    51	
    52	        snapshots.Add(targetSnapshot);
