public abstract class ComparerReproBase : ComponentBase
{
    private readonly IReadOnlyCollection<string> _items = ["test1", "test2", "test3"];
    private IReadOnlyCollection<string?> _selectedItems = ["test1"];

    protected abstract IEqualityComparer<string?> Comparer { get; }

    protected override void BuildRenderTree(RenderTreeBuilder builder)
    {
        builder.OpenComponent<MudSelect<string>>(0);
        builder.AddAttribute(1, nameof(MudSelect<string>.SelectedValues), _selectedItems);
        builder.AddAttribute(2, nameof(MudSelect<string>.SelectedValuesChanged), EventCallback.Factory.Create<IReadOnlyCollection<string?>?>(this, values => _selectedItems = values ?? []));
        builder.AddAttribute(3, nameof(MudSelect<string>.Label), "Test");
        builder.AddAttribute(4, nameof(MudSelect<string>.Variant), Variant.Outlined);
        builder.AddAttribute(5, nameof(MudSelect<string>.MultiSelection), true);
        builder.AddAttribute(6, nameof(MudSelect<string>.Comparer), Comparer);
        builder.AddAttribute(7, nameof(MudSelect<string>.ChildContent), (RenderFragment)(childBuilder =>
        {
            var sequence = 0;
            foreach (var item in _items)
            {
                childBuilder.OpenComponent<MudSelectItem<string>>(sequence++);
                childBuilder.AddAttribute(sequence++, nameof(MudSelectItem<string>.Value), item);
                childBuilder.CloseComponent();
            }
        }));
        builder.CloseComponent();
    }
}

