{
    private readonly IEqualityComparer<string?> _comparer = new ReproStringComparer();

    protected override IEqualityComparer<string?> Comparer => _comparer;
}

public sealed class InlineComparerRepro : ComparerReproBase
{
    protected override IEqualityComparer<string?> Comparer => new ReproStringComparer();
}

public sealed class ReproStringComparer : IEqualityComparer<string?>
{
    public bool Equals(string? x, string? y)
    {
        if (x is null && y is null)
        {
            return true;
        }

        if (x is null || y is null)
        {
            return false;
        }

        return x.GetType() == y.GetType() && x.Equals(y);
    }

    public int GetHashCode(string? obj) => obj?.GetHashCode() ?? 0;
}
